// Map country codes to your markets
const MARKET_MAP = { NL: 'NL', FR: 'FR', DE: 'DE', ES: 'ES', IT: 'IT' };

// Determine campaign type from campaign name
function getCampaignType(campaignName = '') {
  const n = campaignName.toLowerCase();
  if (n.includes('cbo') || n.includes('scaling')) return 'CBO';
  if (n.includes('abo') || n.includes('test')) return 'ABO';
  return 'ABO'; // default
}

function getMetric(actions, actionType) {
  if (!actions) return 0;
  const a = actions.find(x => x.action_type === actionType);
  return a ? parseFloat(a.value) : 0;
}

const insights = $input.all();
const records = [];

for (const item of insights) {
  const data = item.json;
  const rows = Array.isArray(data.data) ? data.data : [data];

  for (const row of rows) {
    const country = (row.country || '').toUpperCase();
    const market = MARKET_MAP[country];
    if (!market) continue; // skip markets we don't track

    const spend = parseFloat(row.spend || 0);
    const revenue = getMetric(row.action_values, 'offsite_conversion.fb_pixel_purchase');
    const conversions = getMetric(row.actions, 'offsite_conversion.fb_pixel_purchase');
    const impressions = parseInt(row.impressions || 0);
    const clicks = parseInt(row.clicks || 0);

    // Thumbstop = 3s video views / impressions
    const threeSecViews = getMetric(row.video_thruplay_watched_actions, 'video_view');
    const thumbstop = impressions > 0 ? threeSecViews / impressions : null;

    records.push({
      meta_ad_id: row.ad_id,
      market,
      campaign_type: getCampaignType(row.campaign_name),
      date: row.date_stop, // yesterday's date
      spend,
      revenue,
      conversions,
      impressions,
      clicks,
      thumbstop_rate: thumbstop,
    });
  }
}

return [{ json: { records } }];
